import{_ as e,a,b as r,c as t,d as i,e as l,f as o,g as s}from"./chunks/asktug_mva.6abe5238.js";import{_ as n,c as h,o as c,N as d}from"./chunks/framework.0799945b.js";const q=JSON.parse('{"title":"博客及博主简介","description":"","frontmatter":{},"headers":[],"relativePath":"zh/index.md"}'),p={name:"zh/index.md"},_=d('<h1 id="博客及博主简介" tabindex="-1">博客及博主简介 <a class="header-anchor" href="#博客及博主简介" aria-label="Permalink to &quot;博客及博主简介&quot;">​</a></h1><p><img src="'+e+'" alt="header"></p><ul><li>Bilibili：<a href="https://space.bilibili.com/318184941?spm_id_from=333.1007.0.0" target="_blank" rel="noreferrer">@JanDBNest</a></li><li>技术博客：<a href="http://www.dbnest.net/zh/tidb/07TiDB-%E6%BA%90%E7%A0%81%E9%98%85%E8%AF%BB/8-1TiDB/02TiDB%20Point_Get%20%E7%82%B9%E6%9F%A5%E7%9A%84%E4%B8%80%E7%94%9F.html" target="_blank" rel="noreferrer">TiDB Point_Get 点查的一生</a></li><li>Github：<a href="https://github.com/jansu-dev" target="_blank" rel="noreferrer">https://github.com/jansu-dev</a></li><li>Email：jan-su-dev@outlook.com</li><li>Wechat：xh9836(<code>请说明你的来意及获取位置</code>)</li></ul><h2 id="博客内容" tabindex="-1">博客内容 <a class="header-anchor" href="#博客内容" aria-label="Permalink to &quot;博客内容&quot;">​</a></h2><ol><li><strong>是什么</strong>：主要是记录个人在 <strong>数据库方面知识</strong>、<strong>英语笔记</strong>，及 <strong>值得分享的内容</strong>。</li><li><strong>为什么</strong>：期望以 博客 的形式，克服自己的遗忘，并给志趣相投的伙伴提供资料，也纠错自己。</li><li><strong>怎么做</strong>：在导航栏 <strong>“文档笔记”</strong> 中，记录学习过程，也欢迎大家在 <strong>“社区”</strong> 中留下你的意见和问题。</li></ol><h2 id="技术缘起" tabindex="-1">技术缘起 <a class="header-anchor" href="#技术缘起" aria-label="Permalink to &quot;技术缘起&quot;">​</a></h2><ol><li>初中时，读到一本书《马云创业启示录》（PS：虽然书中内容与技术关系不大）让我看到了，互联网带给中国的改变。随后我也增开过几次网店，并赚了些零花钱😁，这番经历导致了我在大学时毅然决定走向 IT 相关专业，并在大学期间协助老师使用 <strong>Python + Scrapy + chrome-driver + phantomjs</strong> 爬取 Boss 直聘，51 job 等信息用于分析，学院课程改革方向与市场需求匹配。</li><li>临近毕业，在老师的推荐下走进数据库行业。初入行业，选择了稳定且周边生态健全的 Oracle 学习，但当时做的是数据库管理员（DBA），个人觉得还是应该深入数据库内部（代码层）去了解一下，就像 <strong><code>What I cannot create, I do not understand. -- Richard Phillips Feynman</code></strong> 说的一样，不会造便不能真正理解。随后，有幸来到 <a href="https://baike.baidu.com/item/PingCAP/60056692?fr=aladdin" target="_blank" rel="noreferrer">PingCAP</a> 工作，学习新一代分布式 HTAP 数据库。</li><li>秉承深入内核学习思路，在这个过程中逐渐了解 Golang, Rust, NodeJs 等语言，技术之路很有趣，是推动世界前进的重要力量。</li></ol><hr><h2 id="开源项目" tabindex="-1">开源项目 <a class="header-anchor" href="#开源项目" aria-label="Permalink to &quot;开源项目&quot;">​</a></h2><p>（对于程序员来讲，没有什么比Show me the code能有说服力了）</p><ul><li><a href="https://github.com/jansu-dev/tihc" target="_blank" rel="noreferrer">TiHC</a>：TiHC (TiDB Healthy Check) 是一个开源的、基于 rust 构建的 TiDB 巡检工具，目的是为缩短询价时间，提高交付效率。借鉴 TiDB 官方工具 tiup 分发 ssh 的原理，分布式采集各节点信息并整合 grafana 监控，最终生成可交付的巡检 Office Doc 文件。</li><li><a href="https://github.com/jansu-dev/mbr" target="_blank" rel="noreferrer">MBR</a>：MBR(MicroBR) 是由 Rust 构建并模仿 TiDB BR 部分功能的小玩具，实现了 BR 部分接口和功能的 TiDB 物理备份工具。</li></ul><h2 id="技术文章" tabindex="-1">技术文章 <a class="header-anchor" href="#技术文章" aria-label="Permalink to &quot;技术文章&quot;">​</a></h2><ul><li><a href="https://tidb.net/blog/d6444c63" target="_blank" rel="noreferrer">SQL PointGet 的一生：TiDB 中 点查 如何经过 mysql protocol、parser、compile、executor、scheduler 等模块处理</a></li><li><a href="https://tidb.net/blog/70588c4c" target="_blank" rel="noreferrer">TiCDC系列分享：简述产生背景及使用概况</a></li><li><a href="https://tidb.net/blog/9568ace1" target="_blank" rel="noreferrer">TiCDC系列分享：剖析同步模型与基本架构</a></li></ul><hr><h2 id="视频演讲" tabindex="-1">视频演讲 <a class="header-anchor" href="#视频演讲" aria-label="Permalink to &quot;视频演讲&quot;">​</a></h2><ol><li><a href="https://asktug.com/t/topic/998896#h-2" target="_blank" rel="noreferrer">【2022年】TiDB 社区年度总结 - 版主 - 苏志鹏（jansu-dev）</a></li></ol><hr><h2 id="证书荣誉" tabindex="-1">证书荣誉 <a class="header-anchor" href="#证书荣誉" aria-label="Permalink to &quot;证书荣誉&quot;">​</a></h2><ol><li><p>Oracle OCP <img src="'+a+'" alt="oracle_ocp"></p></li><li><p>TiDB PTCP(chinese version) <img src="'+r+'" alt="tidb_ptcp_chinest"></p></li><li><p>TiDB PTCA(english/global version) <img src="'+t+'" alt="tidb_ptca_global"></p></li><li><p>TiDB PTCP(english/global version 6) <img src="'+i+'" alt="tidb_ptcp_global"></p></li><li><p>PostgreSQL PGCA <img src="'+l+'" alt="pg_pgca"></p></li><li><p>PostgreSQL PGCE <img src="'+o+'" alt="pg_pgce"></p></li><li><p>AskTUG MVA: <a href="https://asktug.com/t/topic/273501" target="_blank" rel="noreferrer">相关链接</a><img src="'+s+'" alt="asktug_mva"></p></li></ol><hr><h2 id="关于生活" tabindex="-1">关于生活 <a class="header-anchor" href="#关于生活" aria-label="Permalink to &quot;关于生活&quot;">​</a></h2>',21),g=[_];function m(b,u,f,P,B,T){return c(),h("div",null,g)}const C=n(p,[["render",m]]);export{q as __pageData,C as default};
